15→/**
16→ * EvidenceRepository — immutable storage for training evidence records.
17→ * No update or delete methods: evidence is append-only by design.
18→ */
19→
20→import type { StorageAdapter } from "../storage/adapter.js";
21→import type { TrainingEvidence } from "./schemas.js";
22→
23→const EVIDENCE_COLLECTION = "evidence";
24→
25→export interface EvidenceListFilters {
26→  employeeId?: string;
27→  from?: string; // ISO datetime
28→  to?: string; // ISO datetime
29→  outcome?: string; // "passed" | "exhausted" | "abandoned"
30→  limit?: number;
31→  offset?: number;
32→}
33→
34→export class EvidenceRepository {
35→  constructor(private readonly storage: StorageAdapter) {}
36→
37→  async create(tenantId: string, data: Omit<TrainingEvidence, "id">): Promise<TrainingEvidence> {
38→    return this.storage.create<Omit<TrainingEvidence, "id">>(
39→      tenantId,
40→      EVIDENCE_COLLECTION,
41→      data,
42→    ) as Promise<TrainingEvidence>;
43→  }
44→
45→  async findBySessionId(tenantId: string, sessionId: string): Promise<TrainingEvidence | null> {
46→    const results = await this.storage.findMany<TrainingEvidence>(tenantId, EVIDENCE_COLLECTION, {
47→      where: { sessionId },
48→      limit: 1,
49→    });
50→    return results[0] ?? null;
51→  }
52→
53→  async findById(tenantId: string, id: string): Promise<TrainingEvidence | null> {
54→    return this.storage.findById<TrainingEvidence>(tenantId, EVIDENCE_COLLECTION, id);
55→  }
56→
57→  async listByTenant(
58→    tenantId: string,
59→    filters: EvidenceListFilters = {},
60→  ): Promise<{ items: TrainingEvidence[]; total: number }> {
61→    const query: Record<string, unknown> = {};
62→    if (filters.employeeId) {
63→      query.employeeId = filters.employeeId;
64→    }
65→
66→    let results = await this.storage.findMany<TrainingEvidence>(tenantId, EVIDENCE_COLLECTION, {
67→      where: Object.keys(query).length > 0 ? query : undefined,
68→      orderBy: [{ field: "generatedAt", direction: "desc" }],
69→    });
70→
71→    // Post-filter: date range
72→    const fromDate = filters.from;
73→    if (fromDate) {
74→      results = results.filter((r) => r.generatedAt >= fromDate);
75→    }
76→    const toDate = filters.to;
77→    if (toDate) {
78→      results = results.filter((r) => r.generatedAt <= toDate);
79→    }
80→    // Post-filter: outcome
81→    if (filters.outcome) {
82→      results = results.filter((r) => r.evidence.session.status === filters.outcome);
83→    }
84→
85→    const total = results.length;
86→    const offset = filters.offset ?? 0;
87→    const limit = filters.limit ?? 20;
88→    const items = results.slice(offset, offset + limit);
89→
90→    return { items, total };
91→  }
92→}
