15→import { createHash } from "node:crypto";
16→
17→/**
18→ * Computes a SHA-256 hash of the given evidence body using canonical JSON
19→ * (keys sorted alphabetically at every nesting level).
20→ */
21→export function computeContentHash(evidenceBody: Record<string, unknown>): string {
22→  const canonical = JSON.stringify(evidenceBody, (_key: string, value: unknown) => {
23→    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
24→      return Object.keys(value as Record<string, unknown>)
25→        .sort()
26→        .reduce<Record<string, unknown>>((sorted, k) => {
27→          sorted[k] = (value as Record<string, unknown>)[k];
28→          return sorted;
29→        }, {});
30→    }
31→    return value;
32→  });
33→
34→  return createHash("sha256").update(canonical).digest("hex");
35→}
