15→/**
16→ * Sign-in API route — initiates OIDC authorization code flow.
17→ * FR-001: Redirects browser to IdP authorization endpoint.
18→ * FR-006: Returns generic 404 for invalid tenant slugs (enumeration protection).
19→ */
20→
21→import { OIDCAdapter } from "@/auth/adapters/oidc-adapter";
22→import { createAuthConfigErrorEvent, logAuthEvent } from "@/auth/audit";
23→import { validateTenantSlug } from "@/auth/tenant-validation";
24→import { NextResponse } from "next/server";
25→
26→// Storage adapter instance — in production this would be injected
27→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
28→
29→const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
30→
31→const oidcAdapter = new OIDCAdapter();
32→
33→export async function GET(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
34→  const { tenant: tenantSlug } = await params;
35→
36→  // Validate tenant slug — generic 404 prevents enumeration
37→  const lookup = validateTenantSlug(tenantSlug);
38→  if (!lookup.valid) {
39→    return NextResponse.json({ error: "Organization not found." }, { status: 404 });
40→  }
41→
42→  const { tenant } = lookup;
43→
44→  try {
45→    const result = await oidcAdapter.initiateSignIn(request, tenant);
46→
47→    const response = NextResponse.redirect(result.redirectUrl);
48→
49→    // Set temporary auth state cookie
50→    if (result.cookies) {
51→      for (const [name, value] of Object.entries(result.cookies)) {
52→        response.cookies.set(name, value, {
53→          httpOnly: true,
54→          secure: process.env.NODE_ENV === "production",
55→          sameSite: "lax",
56→          path: "/",
57→          maxAge: 600, // 10 minutes
58→        });
59→      }
60→    }
61→
62→    return response;
63→  } catch (error) {
64→    // Log config error and redirect to error page
65→    const isMissing = error instanceof Error && error.message.includes("not configured");
66→    const auditReason = isMissing ? "missing-oidc-config" : "invalid-oidc-config";
67→    const redirectCode = isMissing ? "missing_config" : "invalid_config";
68→
69→    await storage.initialize();
70→    await logAuthEvent(storage, createAuthConfigErrorEvent(tenantSlug, auditReason, request));
71→
72→    return NextResponse.redirect(
73→      new URL(`/${tenantSlug}/auth/error?code=${redirectCode}`, request.url),
74→    );
75→  }
76→}
