 63→// ---------------------------------------------------------------------------
 64→// POST — T013: Start a new training session; T022: Remediation
 65→// ---------------------------------------------------------------------------
 66→
 67→export async function POST(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
 68→  const { tenant: tenantSlug } = await params;
 69→  const tenantId = request.headers.get("x-tenant-id");
 70→  const employeeId = request.headers.get("x-employee-id");
 71→
 72→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
 73→    return NextResponse.json(
 74→      { error: "unauthorized", message: "Not authenticated" },
 75→      { status: 401 },
 76→    );
 77→  }
 78→
 79→  // Initialise repositories per-request to avoid connection sharing
 80→  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 81→  const profileRepo = new ProfileRepository(storage);
 82→  const sessionRepo = new SessionRepository(storage);
 83→
 84→  await storage.initialize();
 85→
 86→  try {
 87→    // 1. Check for existing active session — 409 if one exists
 88→    const existingSession = await sessionRepo.findActiveSession(tenantId, employeeId);
 89→    if (existingSession) {
 90→      return NextResponse.json(
 91→        { error: "conflict", message: "An active training session already exists" },
 92→        { status: 409 },
 93→      );
 94→    }
 95→
 96→    // Resolve tenant config (needed for both fresh and remediation paths)
 97→    const snapshot = getSnapshot();
 98→    const tenant = snapshot?.tenants.get(tenantSlug);
 99→    if (!tenant) {
100→      return NextResponse.json(
101→        { error: "not_found", message: "Tenant not found" },
102→        { status: 404 },
103→      );
104→    }
105→    const model = resolveModel(tenant);
106→    const maxModules = tenant.settings.training?.maxModules ?? 8;
107→    const maxAttempts = tenant.settings.training?.maxAttempts ?? 3;
108→    const enableRemediation = tenant.settings.training?.enableRemediation ?? true;
109→
110→    // 2. T022: Check for a failed session with attempts remaining — start remediation
111→    const history = await sessionRepo.findSessionHistory(tenantId, employeeId, { limit: 10 });
112→    const failedSession =
113→      history.find((s) => s.status === "failed" && s.attemptNumber < maxAttempts) ?? null;
114→
115→    if (failedSession) {
116→      // 2a. Remediation must be enabled
117→      if (!enableRemediation) {
118→        return NextResponse.json(
119→          { error: "conflict", message: "Remediation is not enabled for this tenant" },
120→          { status: 409 },
121→        );
122→      }
123→
124→      // 2b. Find confirmed role profile — 404 if none
125→      const profile = await profileRepo.findByEmployee(tenantId, employeeId);
126→      if (!profile) {
127→        return NextResponse.json(
128→          { error: "not_found", message: "No confirmed role profile found" },
129→          { status: 404 },
130→        );
131→      }
132→
133→      // 2c. Generate remediation curriculum focused on weak areas
134→      const weakAreas = failedSession.weakAreas ?? [];
135→      let remediationCurriculum: Awaited<ReturnType<typeof generateRemediationCurriculum>>;
136→      try {
137→        remediationCurriculum = await generateRemediationCurriculum(
138→          weakAreas,
139→          profile,
140→          { maxModules },
141→          model,
142→        );
143→      } catch (error) {
144→        if (error instanceof RemediationPlanError) {
145→          if (error.code === "ai_unavailable") {
146→            return NextResponse.json(
147→              { error: "ai_unavailable", message: "AI service temporarily unavailable" },
148→              { status: 503 },
149→            );
150→          }
151→          return NextResponse.json(
152→            { error: "planning_failed", message: error.message },
153→            { status: 422 },
154→          );
155→        }
156→        return NextResponse.json(
157→          { error: "internal_error", message: "An unexpected error occurred" },
158→          { status: 500 },
159→        );
160→      }
161→
162→      // 2d. Increment attemptNumber and transition the failed session through remediation states
163→      const newAttemptNumber = failedSession.attemptNumber + 1;
164→
165→      // Transition: failed → in-remediation
166→      transitionSession(failedSession.status, "remediation-started");
167→      // Transition: in-remediation → in-progress
168→      transitionSession("in-remediation", "remediation-modules-ready");
169→
170→      // 2e. Update the existing session with new curriculum, status, and attemptNumber
171→      let updatedSession: Awaited<ReturnType<typeof sessionRepo.updateSession>>;
172→      try {
173→        updatedSession = await sessionRepo.updateSession(
174→          tenantId,
175→          failedSession.id,
176→          {
177→            status: "in-progress",
178→            attemptNumber: newAttemptNumber,
179→            curriculum: remediationCurriculum,
180→            weakAreas: null,
181→            aggregateScore: null,
182→            completedAt: null,
183→          },
184→          failedSession.version,
185→        );
186→      } catch (err) {
187→        if (err instanceof VersionConflictError) {
188→          return NextResponse.json(
189→            { error: "conflict", message: "Session was modified by another request" },
190→            { status: 409 },
191→          );
192→        }
193→        throw err;
194→      }
195→
196→      // 2f. Create new module records for the remediation curriculum
197→      const now = new Date().toISOString();
198→      const remediationModuleData = remediationCurriculum.modules.map((m, i) => ({
199→        tenantId,
200→        sessionId: failedSession.id,
201→        moduleIndex: i,
202→        title: m.title,
203→        topicArea: m.topicArea,
204→        jobExpectationIndices: m.jobExpectationIndices,
205→        status: "locked" as const,
206→        content: null,
207→        scenarioResponses: [],
208→        quizAnswers: [],
209→        moduleScore: null,
210→        version: 1,
211→        createdAt: now,
212→        updatedAt: now,
213→      }));
214→
215→      const remediationModules = await sessionRepo.createModules(tenantId, remediationModuleData);
216→
217→      // 2g. Log remediation audit event
218→      await logRemediationInitiated(
219→        storage,
220→        tenantId,
221→        employeeId,
222→        failedSession.id,
223→        newAttemptNumber,
224→        weakAreas.length,
225→        weakAreas,
226→      );
227→
228→      // 2h. Return 201 with updated session + new modules
229→      return NextResponse.json(
230→        { session: updatedSession, modules: remediationModules.map(stripServerFields) },
231→        { status: 201 },
232→      );
233→    }
234→
235→    // 3. No active session and no failed session with attempts remaining — fresh session
236→    // Find confirmed role profile — 404 if none
237→    const profile = await profileRepo.findByEmployee(tenantId, employeeId);
238→    if (!profile) {
239→      return NextResponse.json(
240→        { error: "not_found", message: "No confirmed role profile found" },
241→        { status: 404 },
242→      );
243→    }
244→
245→    // 4. Generate curriculum via AI
246→    let curriculum: Awaited<ReturnType<typeof generateCurriculum>>;
247→    try {
248→      curriculum = await generateCurriculum(profile, { maxModules }, model);
249→    } catch (error) {
250→      if (error instanceof CurriculumGenerationError) {
251→        if (error.code === "ai_unavailable") {
252→          return NextResponse.json(
253→            { error: "ai_unavailable", message: "AI service temporarily unavailable" },
254→            { status: 503 },
255→          );
256→        }
257→        return NextResponse.json(
258→          { error: "generation_failed", message: error.message },
259→          { status: 422 },
260→        );
261→      }
262→      return NextResponse.json(
263→        { error: "internal_error", message: "An unexpected error occurred" },
264→        { status: 500 },
265→      );
266→    }
267→
268→    // 5. Create session record
269→    const now = new Date().toISOString();
270→    const session = await sessionRepo.createSession(tenantId, {
271→      tenantId,
272→      employeeId,
273→      roleProfileId: profile.id,
274→      roleProfileVersion: profile.version,
275→      configHash: snapshot?.configHash ?? "unknown",
276→      appVersion: process.env.APP_VERSION ?? "unknown",
277→      status: "in-progress",
278→      attemptNumber: 1,
279→      curriculum,
280→      aggregateScore: null,
281→      weakAreas: null,
282→      version: 1,
283→      createdAt: now,
284→      updatedAt: now,
285→      completedAt: null,
286→    });
287→
288→    // 6. Create module records for each curriculum module
289→    const moduleData = curriculum.modules.map((m, i) => ({
290→      tenantId,
291→      sessionId: session.id,
292→      moduleIndex: i,
293→      title: m.title,
294→      topicArea: m.topicArea,
295→      jobExpectationIndices: m.jobExpectationIndices,
296→      status: "locked" as const,
297→      content: null,
298→      scenarioResponses: [],
299→      quizAnswers: [],
300→      moduleScore: null,
301→      version: 1,
302→      createdAt: now,
303→      updatedAt: now,
304→    }));
305→
306→    const modules = await sessionRepo.createModules(tenantId, moduleData);
307→
308→    // 7. Log audit event
309→    await logSessionStarted(
310→      storage,
311→      tenantId,
312→      employeeId,
313→      session.id,
314→      1,
315→      profile.version,
316→      snapshot?.configHash ?? "unknown",
317→    );
318→
319→    // 8. Return 201 with session + modules
320→    return NextResponse.json({ session, modules: modules.map(stripServerFields) }, { status: 201 });
321→  } finally {
322→    await storage.close();
323→  }
324→}
