326→// ---------------------------------------------------------------------------
327→// GET — T014: Get current session state
328→// ---------------------------------------------------------------------------
329→
330→export async function GET(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
331→  const { tenant: tenantSlug } = await params;
332→  const tenantId = request.headers.get("x-tenant-id");
333→  const employeeId = request.headers.get("x-employee-id");
334→
335→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
336→    return NextResponse.json(
337→      { error: "unauthorized", message: "Not authenticated" },
338→      { status: 401 },
339→    );
340→  }
341→
342→  // Initialise repositories per-request to avoid connection sharing
343→  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
344→  const sessionRepo = new SessionRepository(storage);
345→
346→  await storage.initialize();
347→
348→  try {
349→    // Parse query parameters
350→    const url = new URL(request.url);
351→    const isHistory = url.searchParams.get("history") === "true";
352→
353→    // T030: History mode — return all sessions with their modules
354→    if (isHistory) {
355→      const sessions = await sessionRepo.findSessionHistory(tenantId, employeeId);
356→      const sessionsWithModules = await Promise.all(
357→        sessions.map(async (sess) => {
358→          const modules = await sessionRepo.findModulesBySession(tenantId, sess.id);
359→          const clientModules = modules.map(stripServerFields);
360→          return { session: sess, modules: clientModules };
361→        }),
362→      );
363→      return NextResponse.json(sessionsWithModules);
364→    }
365→
366→    // T014: Default mode — return active or most recent session
367→    let session = await sessionRepo.findActiveSession(tenantId, employeeId);
368→    if (!session) {
369→      const history = await sessionRepo.findSessionHistory(tenantId, employeeId, { limit: 1 });
370→      session = history[0] ?? null;
371→    }
372→
373→    if (!session) {
374→      return NextResponse.json(
375→        { error: "not_found", message: "No training session found" },
376→        { status: 404 },
377→      );
378→    }
379→
380→    // 2. Find modules for this session
381→    const modules = await sessionRepo.findModulesBySession(tenantId, session.id);
382→
383→    // 3. Strip server-only fields (correct answers, rubrics) from module content
384→    const clientModules = modules.map(stripServerFields);
385→
386→    // 4. Read maxAttempts from tenant config so the UI can display accurate attempt counts
387→    const tenantConfig = getSnapshot()?.tenants.get(tenantSlug);
388→    const maxAttempts = tenantConfig?.settings.training?.maxAttempts ?? 3;
389→
390→    return NextResponse.json({ session, modules: clientModules, maxAttempts });
391→  } finally {
392→    await storage.close();
393→  }
394→}
