15→/**
16→ * List evidence API route.
17→ * GET /api/training/{tenant}/evidence
18→ * Returns paginated evidence summaries for admin/compliance users.
19→ */
20→
21→import { EvidenceRepository } from "@/evidence/evidence-repository";
22→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
23→import { NextResponse } from "next/server";
24→
25→export async function GET(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
26→  const { tenant: tenantSlug } = await params;
27→  const tenantId = request.headers.get("x-tenant-id");
28→  const employeeId = request.headers.get("x-employee-id");
29→
30→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
31→    return NextResponse.json(
32→      { error: "unauthorized", message: "Not authenticated" },
33→      { status: 401 },
34→    );
35→  }
36→
37→  const role = request.headers.get("x-employee-role") ?? "employee";
38→  if (role === "employee") {
39→    return NextResponse.json(
40→      { error: "forbidden", message: "Admin access required" },
41→      { status: 403 },
42→    );
43→  }
44→
45→  const url = new URL(request.url);
46→  const filterEmployeeId = url.searchParams.get("employeeId") ?? undefined;
47→  const outcome = url.searchParams.get("outcome") ?? undefined;
48→  const from = url.searchParams.get("from") ?? undefined;
49→  const to = url.searchParams.get("to") ?? undefined;
50→  const limit = Math.min(Number.parseInt(url.searchParams.get("limit") ?? "20", 10) || 20, 100);
51→  const offset = Number.parseInt(url.searchParams.get("offset") ?? "0", 10) || 0;
52→
53→  const storage = new SQLiteAdapter({
54→    dbPath: process.env.DB_PATH ?? "data/jem.db",
55→  });
56→  const evidenceRepo = new EvidenceRepository(storage);
57→  await storage.initialize();
58→
59→  try {
60→    const { items, total } = await evidenceRepo.listByTenant(tenantId, {
61→      employeeId: filterEmployeeId,
62→      outcome,
63→      from,
64→      to,
65→      limit,
66→      offset,
67→    });
68→
69→    // Map to summary format (strip full evidence body)
70→    const summaries = items.map((item) => ({
71→      id: item.id,
72→      sessionId: item.sessionId,
73→      employeeId: item.employeeId,
74→      schemaVersion: item.schemaVersion,
75→      contentHash: item.contentHash,
76→      generatedAt: item.generatedAt,
77→      outcome: {
78→        status: item.evidence.session.status,
79→        aggregateScore: item.evidence.outcome.aggregateScore,
80→        passed: item.evidence.outcome.passed,
81→      },
82→    }));
83→
84→    return NextResponse.json({ items: summaries, total, limit, offset }, { status: 200 });
85→  } finally {
86→    await storage.close();
87→  }
88→}
