34→    return NextResponse.json(
35→      { error: "unauthorized", message: "Not authenticated" },
36→      { status: 401 },
37→    );
38→  }
39→
40→  const role = request.headers.get("x-employee-role") ?? "employee";
41→
42→  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
43→  const evidenceRepo = new EvidenceRepository(storage);
44→
45→  await storage.initialize();
46→
47→  try {
48→    const evidence = await evidenceRepo.findBySessionId(tenantId, sessionId);
