### 6. API Route Patterns

**Standard Route Pattern (with auth, tenant validation):**

**File:** `/Users/thamsanqamoyo/Documents/code/jem-open/jem-sec-attest/app/api/training/[tenant]/evidence/route.ts` (LIST)

```typescript
export async function GET(
  request: Request,
  { params }: { params: Promise<{ tenant: string }> }
) {
  const { tenant: tenantSlug } = await params;
  const tenantId = request.headers.get("x-tenant-id");
  const employeeId = request.headers.get("x-employee-id");
  const role = request.headers.get("x-employee-role") ?? "employee";

  // 1. Validate auth
  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
    return NextResponse.json(
      { error: "unauthorized", message: "Not authenticated" },
      { status: 401 },
    );
  }

  // 2. Check role/permissions
  if (role === "employee") {
    return NextResponse.json(
      { error: "forbidden", message: "Admin access required" },
      { status: 403 },
    );
  }

  // 3. Initialize storage adapter at module scope
  const storage = new SQLiteAdapter({
    dbPath: process.env.DB_PATH ?? "data/jem.db",
  });
  await storage.initialize();

  try {
    // 4. Query repository
    const { items, total } = await evidenceRepo.listByTenant(tenantId, { /* filters */ });

    // 5. Return paginated response
    return NextResponse.json({ items, total, limit, offset }, { status: 200 });
  } finally {
    await storage.close();
  }
}
```

**File:** `/Users/thamsanqamoyo/Documents/code/jem-open/jem-sec-attest/app/api/training/[tenant]/evidence/[sessionId]/route.ts` (RETRIEVE)

```typescript
export async function GET(
  request: Request,
  { params }: { params: Promise<{ tenant: string; sessionId: string }> },
) {
  const { tenant: tenantSlug, sessionId } = await params;
  const tenantId = request.headers.get("x-tenant-id");
  const employeeId = request.headers.get("x-employee-id");
  const role = request.headers.get("x-employee-role") ?? "employee";

  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
    return NextResponse.json({ error: "unauthorized" }, { status: 401 });
  }

  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
  await storage.initialize();

  try {
    const evidence = await evidenceRepo.findBySessionId(tenantId, sessionId);

    if (!evidence) {
      return NextResponse.json({ error: "not_found" }, { status: 404 });
    }

    // Role-based access: employees see only their own evidence
    if (role === "employee" && evidence.employeeId !== employeeId) {
      return NextResponse.json({ error: "forbidden" }, { status: 403 });
    }

    return NextResponse.json(evidence, { status: 200 });
  } finally {
