```

**File:** `/Users/thamsanqamoyo/Documents/code/jem-open/jem-sec-attest/app/api/training/[tenant]/evidence/[sessionId]/generate/route.ts` (CREATE)

```typescript
export async function POST(
  request: Request,
  { params }: { params: Promise<{ tenant: string; sessionId: string }> },
) {
  // Auth & role checks first
  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
    return NextResponse.json({ error: "unauthorized" }, { status: 401 });
  }
  if (role === "employee") {
    return NextResponse.json({ error: "forbidden" }, { status: 403 });
  }

  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
  await storage.initialize();

  try {
    // Validate session exists and is terminal
    const session = await storage.findById(tenantId, "training_sessions", sessionId);
    if (!TERMINAL_STATUSES.has(session.status)) {
      return NextResponse.json({ error: "conflict" }, { status: 409 });
    }

    // Idempotent: return existing or generate new
    const existing = await evidenceRepo.findBySessionId(tenantId, sessionId);
    if (existing) {
      return NextResponse.json(existing, { status: 200 });
    }

    const evidence = await generateEvidenceForSession(tenantId, sessionId);
    return NextResponse.json(evidence, { status: 201 });
  } finally {
    await storage.close();
  }
}
```

**Pattern Summary:**
- Routes use async params destructuring: `const { tenant: tenantSlug } = await params`
- Auth via headers: `x-tenant-id`, `x-employee-id`, `x-employee-role`
- Tenant slug matches tenantId header: `tenantId !== tenantSlug` → 401
- Error responses: `{ error: string, message?: string }` with status codes
- Query params parsed with `new URL(request.url).searchParams`
- Storage initialized/closed in try-finally block
- `@/` alias imports without `.js` extension per code style guide

