 15→/**
 16→ * Unit tests for GET /api/training/{tenant}/evidence/{sessionId}
 17→ * T011: Returns evidence for a given session
 18→ * T012: Role-based access control (employee, compliance, admin)
 19→ */
 20→
 21→import type { TrainingEvidence } from "@/evidence/schemas";
 22→
 23→// ---------------------------------------------------------------------------
 24→// Mocks (vi.hoisted pattern for module-scope singletons)
 25→// ---------------------------------------------------------------------------
 26→
 27→const { mockStorage, mockEvidenceRepo } = vi.hoisted(() => {
 28→  const mockStorage = {
 29→    initialize: vi.fn().mockResolvedValue(undefined),
 30→    create: vi.fn(),
 31→    findById: vi.fn(),
 32→    findMany: vi.fn(),
 33→    update: vi.fn(),
 34→    delete: vi.fn(),
 35→    transaction: vi.fn().mockImplementation((_t: string, fn: () => unknown) => fn()),
 36→    getMetadata: vi.fn().mockReturnValue({ adapterName: "mock", adapterVersion: "1.0" }),
 37→    close: vi.fn(),
 38→  };
 39→  const mockEvidenceRepo = {
 40→    create: vi.fn(),
 41→    findBySessionId: vi.fn(),
 42→    findById: vi.fn(),
 43→    listByTenant: vi.fn(),
 44→  };
 45→  return { mockStorage, mockEvidenceRepo };
 46→});
 47→
 48→vi.mock("@/storage/sqlite-adapter", () => ({
 49→  SQLiteAdapter: vi.fn().mockImplementation(() => mockStorage),
 50→}));
 51→vi.mock("@/evidence/evidence-repository", () => ({
 52→  EvidenceRepository: vi.fn().mockImplementation(() => mockEvidenceRepo),
 53→}));
 54→
 55→import { GET } from "../../../app/api/training/[tenant]/evidence/[sessionId]/route";
 56→
 57→// ---------------------------------------------------------------------------
 58→// Helpers
 59→// ---------------------------------------------------------------------------
 60→
 61→function makeRequest(
 62→  sessionId: string,
 63→  tenantId?: string,
 64→  employeeId?: string,
 65→  role = "employee",
 66→): Request {
 67→  const url = `http://localhost:3000/api/training/${tenantId ?? "acme"}/evidence/${sessionId}`;
 68→  const headers = new Headers();
 69→  if (tenantId) headers.set("x-tenant-id", tenantId);
 70→  if (employeeId) headers.set("x-employee-id", employeeId);
 71→  headers.set("x-employee-role", role);
 72→  return new Request(url, { method: "GET", headers });
 73→}
 74→
 75→function makeParams(
 76→  tenant: string,
 77→  sessionId: string,
 78→): { params: Promise<{ tenant: string; sessionId: string }> } {
 79→  return { params: Promise.resolve({ tenant, sessionId }) };
 80→}
 81→
 82→function makeEvidence(overrides?: Partial<TrainingEvidence>): TrainingEvidence {
 83→  return {
 84→    id: "evi-0001",
 85→    tenantId: "acme",
 86→    sessionId: "sess-0001",
 87→    employeeId: "emp-100",
 88→    schemaVersion: 1,
 89→    evidence: {
 90→      session: {
 91→        sessionId: "sess-0001",
 92→        employeeId: "emp-100",
 93→        tenantId: "acme",
 94→        attemptNumber: 1,
 95→        totalAttempts: 3,
 96→        status: "passed",
 97→        createdAt: "2026-01-01T00:00:00.000Z",
 98→        completedAt: "2026-01-01T01:00:00.000Z",
 99→      },
100→      policyAttestation: {
101→        configHash: "abc123",
102→        roleProfileId: "rp-001",
103→        roleProfileVersion: 1,
104→        appVersion: "1.0.0",
105→        passThreshold: 0.7,
106→        maxAttempts: 3,
107→      },
108→      modules: [],
109→      outcome: {
110→        aggregateScore: 0.85,
111→        passed: true,
112→        passThreshold: 0.7,
113→        weakAreas: null,
114→        moduleScores: [],
115→      },
116→    },
117→    contentHash: "sha256-abc",
118→    generatedAt: "2026-01-01T01:00:00.000Z",
119→    ...overrides,
120→  };
121→}
122→
123→// ---------------------------------------------------------------------------
124→// Tests
125→// ---------------------------------------------------------------------------
126→
127→describe("GET /api/training/[tenant]/evidence/[sessionId]", () => {
128→  beforeEach(() => {
129→    vi.clearAllMocks();
130→  });
131→
132→  it("returns 200 with evidence for own session (employee)", async () => {
133→    const evidence = makeEvidence();
134→    mockEvidenceRepo.findBySessionId.mockResolvedValue(evidence);
135→
136→    const request = makeRequest("sess-0001", "acme", "emp-100", "employee");
137→    const response = await GET(request, makeParams("acme", "sess-0001"));
138→
139→    expect(response.status).toBe(200);
140→    const body = await response.json();
